// SignaturePad v3.0.0 - Compatible con tablets y móviles
class SignaturePad {
  constructor(canvas, options = {}) {
    this.canvas = canvas;
    this.ctx = canvas.getContext('2d', { willReadFrequently: true });
    this.options = {
      penColor: 'rgb(66, 133, 244)',
      backgroundColor: 'rgb(255, 255, 255)',
      minWidth: 0.5,
      maxWidth: 2.5,
      throttle: 16,
      minDistance: 5,
      ...options
    };
    this.points = [];
    this.isDrawing = false;
    this.lastTime = 0;
    this.lastX = 0;
    this.lastY = 0;
    this._bindEvents();
    this.clear();
  }

  _bindEvents() {
    this.canvas.addEventListener('pointerdown', e => this._handlePointerStart(e));
    this.canvas.addEventListener('pointermove', e => this._handlePointerMove(e));
    this.canvas.addEventListener('pointerup', e => this._handlePointerEnd(e));
    this.canvas.addEventListener('pointerout', e => this._handlePointerEnd(e));
    this.canvas.addEventListener('pointercancel', e => this._handlePointerEnd(e));
  }

  _handlePointerStart(e) {
    e.preventDefault();
    this.isDrawing = true;
    this.points = [];
    const pos = this._getPos(e);
    this.lastX = pos.x;
    this.lastY = pos.y;
    this.lastTime = Date.now();
    this._drawPoint(pos.x, pos.y);
  }

  _handlePointerMove(e) {
    if (!this.isDrawing) return;
    e.preventDefault();
    const now = Date.now();
    if (now - this.lastTime < this.options.throttle) return;
    
    const pos = this._getPos(e);
    const dist = Math.hypot(pos.x - this.lastX, pos.y - this.lastY);
    
    if (dist < this.options.minDistance) return;
    
    this.points.push({ x: pos.x, y: pos.y, t: now });
    this._drawLine(this.lastX, this.lastY, pos.x, pos.y);
    this.lastX = pos.x;
    this.lastY = pos.y;
    this.lastTime = now;
  }

  _handlePointerEnd(e) {
    e.preventDefault();
    this.isDrawing = false;
  }

  _getPos(e) {
    const rect = this.canvas.getBoundingClientRect();
    const clientX = e.clientX !== undefined ? e.clientX : e.touches?.[0]?.clientX || 0;
    const clientY = e.clientY !== undefined ? e.clientY : e.touches?.[0]?.clientY || 0;
    return {
      x: (clientX - rect.left) * (this.canvas.width / rect.width),
      y: (clientY - rect.top) * (this.canvas.height / rect.height)
    };
  }

  _drawPoint(x, y) {
    this.ctx.fillStyle = this.options.penColor;
    this.ctx.beginPath();
    this.ctx.arc(x, y, this.options.minWidth, 0, Math.PI * 2);
    this.ctx.fill();
  }

  _drawLine(x1, y1, x2, y2) {
    this.ctx.strokeStyle = this.options.penColor;
    this.ctx.lineWidth = this.options.maxWidth;
    this.ctx.lineCap = 'round';
    this.ctx.lineJoin = 'round';
    this.ctx.beginPath();
    this.ctx.moveTo(x1, y1);
    this.ctx.lineTo(x2, y2);
    this.ctx.stroke();
  }

  clear() {
    this.ctx.fillStyle = this.options.backgroundColor;
    this.ctx.clearRect(0, 0, this.canvas.width, this.canvas.height);
    this.ctx.fillRect(0, 0, this.canvas.width, this.canvas.height);
    this.points = [];
  }

  isEmpty() {
    return this.points.length === 0;
  }

  toDataURL(type = 'image/png') {
    return this.canvas.toDataURL(type);
  }

  toData() {
    return this.points;
  }

  fromData(pointGroups) {
    this.clear();
    pointGroups.forEach(group => {
      group.forEach((point, index) => {
        if (index === 0) {
          this._drawPoint(point.x, point.y);
        } else {
          const prev = group[index - 1];
          this._drawLine(prev.x, prev.y, point.x, point.y);
        }
      });
    });
  }
}
